   185→    NllOutput {
   186→        regioncx,
   187→        polonius_input: polonius_facts.map(Box::new),
   188→        polonius_output,
   189→        opt_closure_req: closure_region_requirements,
   190→        nll_errors,
   191→        polonius_diagnostics,
   192→    }
   193→}
