                | ty::Alias(_, _)
                | ty::Param(_)
                | ty::Bound(_, _)
                | ty::Infer(_)
                | ty::Error(_)
                | ty::Placeholder(_) => {
                    bug!("When Place is Deref it's type shouldn't be {place_ty:#?}")
                }
            },
            ProjectionElem::Field(_, _) => match place_ty.ty.kind() {

